Window:







        @default
        {
            FontFamily = "Segoe UI";
            FontSize = 14;
            Foreground = White;
        }



        @default
        {
            Background = $PanelBrush;
            BorderBrush = $PanelEdgeBrush;
            BorderThickness = 1;
            Padding = 12;
        }

        @when IsMouseOver
        {
            @if value == True
            {
                Background = $HoverBrush;
                BorderBrush = $AccentBrush;
            }
        }



@when WindowState
{
    @if value == Normal { BorderBrush = $PanelEdgeBrush; }
    @if value == Maximized { BorderBrush = $AccentBrush; }
}

@when $DataContext.IsReady
{
    @if value == True { Background = "20,28,38"; }
    @if value == False { Background = "12,16,24"; }
}





        Lifecycle handlers have not run yet.










                @default
                {
                    Foreground = $AccentBrush;
                }



        @when $CustomBadge
        {
            @if value != $AccentBrush { Padding = 16; }
        }

        @when $DataContext.IsReady
        {
            @if value == True
            {
                @when IsPointerOver
                {
                    @if value == True { BorderBrush = $AccentBrush; }
                }
            }
        }



                @when $DataContext.Mode
                {
                    @if value == Idle { Text = "Mode: Idle"; }
                    @if value == Running { Text = "Mode: Running"; }
                    @if value == Complete { Text = "Mode: Complete"; }
                }




                    @when $DataContext.Score
                    {
                        @if value < 0 { Text = "Score: negative"; }
                        @if value <= 3 { Text = "Score: low"; }
                        @if value != 0 { IsVisible = True; }
                        @if value > 3 { Text = "Score: medium"; }
                        @if value >= 10 { Text = "Score: high"; }
                        @if value == $DataContext.TargetScore { Text = "Score reached target"; }
                    }



                    @when $DataContext.UserName
                    {
                        @if value == "Ada" { Text = "User: Ada"; }
                        @if value != "Ada" { Text = "User: not Ada"; }
                        @if value < "M" { Foreground = $AccentBrush; }
                        @if value >= "M" { Foreground = White; }
                    }



                    @when $DataContext.Details
                    {
                        @if value == Null { Text = "Details: null"; }
                        @if value != Null { Text = "Details: object available"; }
                    }

                    @when $DataContext.Details.IsHealthy
                    {
                        @if value == True { Text = "Details: healthy"; }
                        @if value == False { Text = "Details: unhealthy"; }
                    }







                    Replace nested observable DataContext object






                    @template
                    {

                            @when $owner.IsMouseOver
                            {
                                Background = $HoverBrush;
                                BorderBrush = $AccentBrush;
                            }


                            @when $owner.IsMouseOver
                            {
                                Foreground = White;
                            }


                    }



                    @when $OpenWindowsButton.parts.$OpenWindowsChrome.IsEnabled
                    {
                        @if value == True { Text = "Template part access: live + reactive"; }
                        @if value == False { Text = "Template part access: observed disabled state"; }
                    }




                @when $DataContext.ShowAdvanced
                {
                    @if value == True
                    {

                    }
                }
